@import "tailwindcss";
@import "fumadocs-ui/css/black.css";
@import "fumadocs-ui/css/preset.css";
@import "fumadocs-openapi/css/preset.css";
@import "@repo/ui/globals.css";

/*
 * Token bridge: fumadocs → Lightfast
 *
 * fumadocs and Lightfast define the same semantic tokens in different color
 * spaces (fd: hex #050505, LF: lab 9.26%). Instead of fighting individual
 * classes, we bridge the entire fd-* namespace to Lightfast equivalents.
 * Every fumadocs component automatically inherits the Lightfast palette.
 *
 * Outside @layer so overrides beat fumadocs' unlayered component styles.
 */
.dark {
  --color-fd-background: var(--background);
  --color-fd-foreground: var(--foreground);
  --color-fd-card: var(--background);
  --color-fd-card-foreground: var(--foreground);
  --color-fd-secondary: var(--secondary);
  --color-fd-secondary-foreground: var(--secondary-foreground);
  --color-fd-muted: var(--muted);
  --color-fd-muted-foreground: var(--muted-foreground);
  --color-fd-border: var(--border);
  --color-fd-accent: var(--accent);
  --color-fd-accent-foreground: var(--accent-foreground);
  --color-fd-popover: var(--card);
  --color-fd-popover-foreground: var(--card-foreground);
  --color-fd-primary: var(--primary);
  --color-fd-primary-foreground: var(--primary-foreground);
  --color-fd-ring: var(--ring);

  --radius-xl: var(--radius-md);
}

/* Tighten rounded-xl to match rounded-md (Tailwind v4 compiles at build time) */
.rounded-xl {
  border-radius: var(--radius-md);
}

/* Kill card/code-block shadows — flat aesthetic */
[class*="bg-fd-card"],
[class*="bg-fd-secondary"],
figure.shiki {
  box-shadow: none;
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* Tighten code example panel spacing in the sticky sidebar */
.prose-no-margin > :first-child {
  margin-top: 0;
}

.prose-no-margin > :last-child {
  margin-bottom: 0;
}

.prose-no-margin > * + * {
  margin-top: 0.5rem;
}

/* Neutralize fumadocs colored badges (method, status, required) */
.dark .text-blue-400,
.dark .text-green-400,
.dark .text-green-600,
.dark .text-yellow-400,
.dark .text-yellow-600,
.dark .text-orange-400,
.dark .text-orange-600,
.dark .text-red-400,
.dark .text-red-600,
.dark .text-blue-600 {
  color: var(--color-fd-muted-foreground);
}

.dark .bg-green-500\/20 {
  background-color: transparent;
}

@layer utilities {
  .font-pp {
    font-family: var(--font-pp-neue-montreal);
  }
}

